Code.Terraform:
```hcl
# WAF Classic Regional Rule Group に少なくとも1つのルールがあることを確認してください
resource "aws_wafregional_rule_group" "<example_resource_name>" {
  name        = "<example_resource_name>"
  metric_name = "<example_resource_name>"

  # 重大: ルールグループが空にならないようにするルールを追加します
  activated_rule {
    priority = 1
    rule_id  = "<example_resource_id>"  # 既存のルールID
    action {
      type = "BLOCK"
    }
  }
}
```
